function [31:0] lfsr_count;
  input [31:0] seed;
  input [31:0] count;
  reg [31:0] counter;
  reg fb_xnor;
  reg [31:0] lfsr_count;
  reg [31:0] data_count;
  begin
    lfsr_count = seed;
    for(counter=1; counter<=count; counter=counter+1)
      begin
        fb_xnor = lfsr_count[30] ^~ lfsr_count[27];
        lfsr_count = {lfsr_count[31-2:0],fb_xnor};
      end
    assign data_count = {lfsr_count, fb_xnor};
  end
endfunction
